module RefModule(  
    input [3:0] g_cost,  
    input [3:0] h_cost,  
    output [4:0] f_cost  
);  
      wire _n01 = g_cost[0] ^ h_cost[0];
  wire _c01 = g_cost[0] & h_cost[0];
  wire _n02 = g_cost[1] ^ h_cost[1] ^ _c01;
  wire _c02 = (g_cost[1] & h_cost[1]) | (g_cost[1] & _c01) | (h_cost[1] & _c01);
  wire _n03 = g_cost[2] ^ h_cost[2] ^ _c02;
  wire _c03 = (g_cost[2] & h_cost[2]) | (g_cost[2] & _c02) | (h_cost[2] & _c02);
  wire _n04 = g_cost[3] ^ h_cost[3] ^ _c03;
  wire _c04 = (g_cost[3] & h_cost[3]) | (g_cost[3] & _c03) | (h_cost[3] & _c03);
  assign f_cost = {_n01, _n02, _n03, _n04};  
endmodule
